//
//  Inlay+SpringAnimator.swift
//  Inlay — shared primitive
//
//  Installed once. Multiple components depend on this file.
//  Do not rename `Inlay` or its members — components reference them by name.
//

import UIKit

/// Root namespace for Inlay's shared primitives and design tokens.
/// Everything shared between components nests under here so that copying
/// two components never produces a duplicate top-level type.
enum Inlay {}

extension Inlay {

    /// A simple, designer-friendly spring token.
    ///
    /// `bounce` is the only knob most people touch:
    ///   - `0.0`  → no overshoot (critically damped)
    ///   - `0.3`  → lively, natural (default)
    ///   - `0.5+` → playful, very springy
    struct Spring {
        var duration: TimeInterval
        var bounce: CGFloat

        init(duration: TimeInterval = 0.5, bounce: CGFloat = 0.3) {
            self.duration = duration
            self.bounce = bounce
        }

        /// A few ready-made springs so callers rarely need raw numbers.
        static let snappy   = Spring(duration: 0.35, bounce: 0.15)
        static let lively   = Spring(duration: 0.5,  bounce: 0.3)
        static let playful  = Spring(duration: 0.6,  bounce: 0.45)
        static let gentle   = Spring(duration: 0.55, bounce: 0.0)
    }

    /// Tiny wrapper over `UIViewPropertyAnimator` that maps a `Spring` token
    /// to a configured spring timing curve. Keeps animation code in every
    /// component down to one line.
    enum SpringAnimator {

        /// Convenience: trailing-closure call site.
        ///   `Inlay.SpringAnimator.animate(.lively) { view.transform = .identity }`
        static func animate(
            _ spring: Inlay.Spring,
            _ animations: @escaping () -> Void
        ) {
            animate(spring, animations: animations, completion: nil)
        }

        static func animate(
            _ spring: Inlay.Spring,
            animations: @escaping () -> Void,
            completion: (() -> Void)?
        ) {
            let damping = dampingRatio(forBounce: spring.bounce)
            let timing = UISpringTimingParameters(dampingRatio: damping)
            let animator = UIViewPropertyAnimator(
                duration: spring.duration,
                timingParameters: timing
            )
            animator.addAnimations(animations)
            if let completion {
                animator.addCompletion { _ in completion() }
            }
            animator.startAnimation()
        }

        /// Maps `bounce` (0...~0.9) to a damping ratio (1...0.1).
        private static func dampingRatio(forBounce bounce: CGFloat) -> CGFloat {
            let clamped = max(0, min(bounce, 0.9))
            return 1 - clamped
        }
    }
}

//
//  FloatingToolbar.swift
//  Inlay — component
//
//  A floating, pill-shaped toolbar with a glass (blur) or solid background,
//  a spring entrance animation, tactile press feedback, and an optional
//  selection highlight.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `FloatingToolbar.Configuration`.
//
//      let toolbar = FloatingToolbar(items: [
//          .init(icon: UIImage(systemName: "house.fill"))     { print("home") },
//          .init(icon: UIImage(systemName: "magnifyingglass")) { print("search") },
//          .init(icon: UIImage(systemName: "bell.fill"))       { print("alerts") },
//          .init(icon: UIImage(systemName: "person.fill"))     { print("profile") },
//      ])
//      view.addSubview(toolbar)
//      NSLayoutConstraint.activate([
//          toolbar.centerXAnchor.constraint(equalTo: view.centerXAnchor),
//          toolbar.bottomAnchor.constraint(
//              equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
//      ])
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class FloatingToolbar: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Tint for item icons and the selection highlight.
        var accentColor: UIColor = .tintColor
        /// Background appearance.
        var background: Background = .glass(.systemThinMaterial)
        /// Corner radius of the pill. Large values read as fully rounded.
        var cornerRadius: CGFloat = 28
        /// Horizontal padding inside the bar.
        var horizontalInset: CGFloat = 16
        /// Spacing between items.
        var itemSpacing: CGFloat = 8
        /// Tappable size of each item.
        var itemSize: CGFloat = 44
        /// Spring used for entrance + press feedback. (Shared design token.)
        var animation: Inlay.Spring = .lively
        /// Whether a highlight follows the last-tapped item.
        var showsSelection: Bool = true
        /// Haptic feedback on tap.
        var hapticsEnabled: Bool = true

        enum Background {
            case glass(UIBlurEffect.Style)
            case solid(UIColor)
        }

        static let `default` = Configuration()
    }

    // MARK: - Item

    /// A single tappable item. Provide an SF Symbol (or any image) and a
    /// closure to run on tap.
    struct Item {
        let icon: UIImage?
        let title: String?
        let onTap: () -> Void

        init(icon: UIImage?, title: String? = nil, onTap: @escaping () -> Void) {
            self.icon = icon
            self.title = title
            self.onTap = onTap
        }
    }

    // MARK: - Private state

    private let configuration: Configuration
    private var items: [Item]
    private let container = UIView()
    private let stack = UIStackView()
    private var backgroundView = UIView()
    private var selectionView: UIView?
    private var buttons: [UIButton] = []
    private var hasAppeared = false

    // MARK: - Init

    init(items: [Item], configuration: Configuration = .default) {
        self.configuration = configuration
        self.items = items
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        self.items = []
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        // Outer view carries the shadow and must NOT clip.
        setUpShadow()

        // Inner container clips the corner radius + background.
        container.translatesAutoresizingMaskIntoConstraints = false
        container.layer.cornerRadius = configuration.cornerRadius
        container.layer.cornerCurve = .continuous
        container.clipsToBounds = true
        addSubview(container)
        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        setUpBackground()
        setUpStack()
        rebuildItems()
        prepareForEntrance()
    }

    private func setUpShadow() {
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.18
        layer.shadowRadius = 18
        layer.shadowOffset = CGSize(width: 0, height: 8)
    }

    private func setUpBackground() {
        switch configuration.background {
        case .glass(let style):
            backgroundView = UIVisualEffectView(effect: UIBlurEffect(style: style))
        case .solid(let color):
            let view = UIView()
            view.backgroundColor = color
            backgroundView = view
        }
        backgroundView.translatesAutoresizingMaskIntoConstraints = false
        backgroundView.isUserInteractionEnabled = false
        container.addSubview(backgroundView)
        NSLayoutConstraint.activate([
            backgroundView.topAnchor.constraint(equalTo: container.topAnchor),
            backgroundView.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            backgroundView.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            backgroundView.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    private func setUpStack() {
        stack.axis = .horizontal
        stack.alignment = .center
        stack.distribution = .fillEqually
        stack.spacing = configuration.itemSpacing
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.isLayoutMarginsRelativeArrangement = true
        stack.layoutMargins = UIEdgeInsets(
            top: 8,
            left: configuration.horizontalInset,
            bottom: 8,
            right: configuration.horizontalInset
        )
        container.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: container.topAnchor),
            stack.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            stack.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            stack.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    // MARK: - Items

    /// Replace the toolbar's items at runtime.
    func setItems(_ items: [Item]) {
        self.items = items
        rebuildItems()
    }

    private func rebuildItems() {
        for view in stack.arrangedSubviews {
            stack.removeArrangedSubview(view)
            view.removeFromSuperview()
        }
        buttons.removeAll()

        for (index, item) in items.enumerated() {
            let button = makeButton(for: item, at: index)
            buttons.append(button)
            stack.addArrangedSubview(button)
        }
    }

    private func makeButton(for item: Item, at index: Int) -> UIButton {
        var config = UIButton.Configuration.plain()
        config.image = item.icon
        config.title = item.title
        config.baseForegroundColor = configuration.accentColor
        config.imagePlacement = .top
        config.imagePadding = 2

        let button = UIButton(configuration: config)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.heightAnchor.constraint(equalToConstant: configuration.itemSize).isActive = true
        button.widthAnchor.constraint(
            greaterThanOrEqualToConstant: configuration.itemSize
        ).isActive = true

        button.addAction(UIAction { [weak self] _ in
            self?.handleTap(at: index, button: button, item: item)
        }, for: .touchUpInside)

        button.addTarget(self, action: #selector(buttonTouchDown(_:)), for: .touchDown)
        button.addTarget(
            self,
            action: #selector(buttonTouchUp(_:)),
            for: [.touchUpInside, .touchUpOutside, .touchCancel]
        )
        return button
    }

    // MARK: - Interaction

    private func handleTap(at index: Int, button: UIButton, item: Item) {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        if configuration.showsSelection {
            moveSelection(to: button)
        }
        item.onTap()
    }

    @objc private func buttonTouchDown(_ sender: UIButton) {
        Inlay.SpringAnimator.animate(configuration.animation) {
            sender.transform = CGAffineTransform(scaleX: 0.9, y: 0.9)
        }
    }

    @objc private func buttonTouchUp(_ sender: UIButton) {
        Inlay.SpringAnimator.animate(configuration.animation) {
            sender.transform = .identity
        }
    }

    private func moveSelection(to button: UIButton) {
        let pill: UIView
        if let existing = selectionView {
            pill = existing
        } else {
            let view = UIView()
            view.backgroundColor = configuration.accentColor.withAlphaComponent(0.18)
            view.layer.cornerRadius = configuration.itemSize / 2
            view.layer.cornerCurve = .continuous
            view.isUserInteractionEnabled = false
            container.insertSubview(view, belowSubview: stack)
            selectionView = view
            pill = view
        }
        container.layoutIfNeeded()
        let target = button.convert(button.bounds, to: container)
        Inlay.SpringAnimator.animate(configuration.animation) {
            pill.frame = target
        }
    }

    // MARK: - Entrance animation

    private func prepareForEntrance() {
        alpha = 0
        transform = CGAffineTransform(scaleX: 0.8, y: 0.8)
    }

    /// Plays the entrance once. Called automatically when added to a window,
    /// but safe to call manually.
    func playEntrance() {
        guard !hasAppeared else { return }
        hasAppeared = true
        Inlay.SpringAnimator.animate(configuration.animation) {
            self.alpha = 1
            self.transform = .identity
        }
    }

    override func didMoveToWindow() {
        super.didMoveToWindow()
        guard window != nil else { return }
        DispatchQueue.main.async { [weak self] in self?.playEntrance() }
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Shadow path tracks the pill shape for crisp, performant shadows.
        layer.shadowPath = UIBezierPath(
            roundedRect: bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath
    }
}

//
//  LoadingIndicator.swift
//  Inlay — component
//
//  A looping loading indicator with three styles: a rotating arc, three pulsing
//  dots, and equalizer bars. Pure CALayer animation, auto-starts on screen,
//  auto-stops when removed. No dependencies.
//
//  ── How to use ────────────────────────────────────────────────────────────
//      let loader = LoadingIndicator()             // .arc, .label color, 40pt
//      view.addSubview(loader)
//      loader.translatesAutoresizingMaskIntoConstraints = false
//      NSLayoutConstraint.activate([
//          loader.centerXAnchor.constraint(equalTo: view.centerXAnchor),
//          loader.centerYAnchor.constraint(equalTo: view.centerYAnchor),
//      ])
//
//      var config = LoadingIndicator.Configuration.default
//      config.style = .dots
//      let dots = LoadingIndicator(configuration: config)
//
//  Dependency: none
//

import UIKit

final class LoadingIndicator: UIView {

    // MARK: - Configuration

    struct Configuration {
        /// Visual style of the loop.
        var style: Style = .arc
        /// Stroke / fill color. Defaults to a dynamic color for dark mode.
        var color: UIColor = .label
        /// Stroke width for the `.arc` style.
        var lineWidth: CGFloat = 3
        /// Intrinsic side length of the indicator.
        var size: CGFloat = 40
        /// One full loop, in seconds.
        var period: CFTimeInterval = 1.0

        static let `default` = Configuration()

        enum Style { case arc, dots, bars }
    }

    // MARK: - State

    private let configuration: Configuration
    private var shapeLayers: [CAShapeLayer] = []
    private var isAnimating = false

    // MARK: - Init

    init(configuration: Configuration = .default) {
        self.configuration = configuration
        super.init(frame: CGRect(x: 0, y: 0,
                                 width: configuration.size, height: configuration.size))
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        super.init(coder: coder)
        setUp()
    }

    override var intrinsicContentSize: CGSize {
        CGSize(width: configuration.size, height: configuration.size)
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        backgroundColor = .clear
        switch configuration.style {
        case .arc:  buildArc()
        case .dots: shapeLayers = buildFills(count: 3)
        case .bars: shapeLayers = buildFills(count: 4)
        }
    }

    private func buildArc() {
        let arc = CAShapeLayer()
        arc.fillColor = UIColor.clear.cgColor
        arc.strokeColor = configuration.color.cgColor
        arc.lineWidth = configuration.lineWidth
        arc.lineCap = .round
        arc.strokeStart = 0
        arc.strokeEnd = 0.25
        layer.addSublayer(arc)
        shapeLayers = [arc]
    }

    private func buildFills(count: Int) -> [CAShapeLayer] {
        (0..<count).map { _ in
            let l = CAShapeLayer()
            l.fillColor = configuration.color.cgColor
            layer.addSublayer(l)
            return l
        }
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        let b = bounds
        switch configuration.style {
        case .arc:
            let inset = configuration.lineWidth / 2
            shapeLayers.first?.frame = b
            shapeLayers.first?.path = UIBezierPath(ovalIn: b.insetBy(dx: inset, dy: inset)).cgPath
        case .dots:
            let d = b.height * 0.30
            let gap = (b.width - d * 3) / 2
            for (i, dot) in shapeLayers.enumerated() {
                dot.frame = CGRect(x: CGFloat(i) * (d + gap), y: (b.height - d) / 2,
                                   width: d, height: d)
                dot.path = UIBezierPath(ovalIn: dot.bounds).cgPath
            }
        case .bars:
            let n = CGFloat(shapeLayers.count)
            let w = b.width / (n * 2 - 1)
            for (i, bar) in shapeLayers.enumerated() {
                bar.frame = CGRect(x: CGFloat(i) * w * 2, y: 0, width: w, height: b.height)
                bar.path = UIBezierPath(roundedRect: bar.bounds, cornerRadius: w / 2).cgPath
            }
        }
    }

    // MARK: - Animation

    /// Starts the loop. Called automatically when the view enters a window.
    func startAnimating() {
        guard !isAnimating else { return }
        isAnimating = true
        setNeedsLayout()
        layoutIfNeeded()
        applyAnimations()
    }

    /// Stops the loop and clears running animations.
    func stopAnimating() {
        isAnimating = false
        shapeLayers.forEach { $0.removeAllAnimations() }
    }

    private func applyAnimations() {
        switch configuration.style {
        case .arc:
            let spin = CABasicAnimation(keyPath: "transform.rotation.z")
            spin.fromValue = 0
            spin.toValue = 2 * Double.pi
            spin.duration = configuration.period
            spin.repeatCount = .infinity
            spin.isRemovedOnCompletion = false
            shapeLayers.first?.add(spin, forKey: "spin")
        case .dots:
            stagger(keyPath: "transform.scale", values: [0.4, 1.0, 0.4], spread: 6)
        case .bars:
            stagger(keyPath: "transform.scale.y", values: [0.3, 1.0, 0.3], spread: 8)
        }
    }

    private func stagger(keyPath: String, values: [CGFloat], spread: Double) {
        for (i, l) in shapeLayers.enumerated() {
            let anim = CAKeyframeAnimation(keyPath: keyPath)
            anim.values = values
            anim.keyTimes = [0, 0.5, 1]
            anim.duration = configuration.period
            anim.repeatCount = .infinity
            anim.beginTime = CACurrentMediaTime() + Double(i) * configuration.period / spread
            anim.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)
            l.add(anim, forKey: "pulse")
        }
    }

    override func didMoveToWindow() {
        super.didMoveToWindow()
        if window != nil { startAnimating() } else { stopAnimating() }
    }
}

//
//  SettingsRow.swift
//  Inlay — component
//
//  A polished settings list row: an SF Symbol in a rounded color tile, a title
//  with optional subtitle, and a trailing accessory (chevron, value, or switch).
//  Springy press feedback and haptics. Drop several into a vertical stack to
//  build a settings screen.
//
//  ── How to use ────────────────────────────────────────────────────────────
//      let row = SettingsRow(
//          model: .init(icon: UIImage(systemName: "bell.badge.fill"),
//                       title: "Notifications",
//                       subtitle: "Sounds, badges, banners",
//                       accessory: .chevron)) {
//          print("open notifications")
//      }
//      let stack = UIStackView(arrangedSubviews: [row])
//      stack.axis = .vertical
//      stack.spacing = 10
//
//      // A switch row:
//      let toggle = SettingsRow(model: .init(
//          icon: UIImage(systemName: "moon.fill"),
//          title: "Dark Mode", accessory: .toggle(true)))
//      toggle.onToggle = { isOn in print("dark mode \(isOn)") }
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class SettingsRow: UIControl {

    // MARK: - Accessory + Model

    enum Accessory {
        case none
        case chevron
        case value(String)
        case toggle(Bool)
    }

    struct Model {
        var icon: UIImage?
        var title: String
        var subtitle: String?
        var accessory: Accessory

        init(icon: UIImage?, title: String,
             subtitle: String? = nil, accessory: Accessory = .chevron) {
            self.icon = icon
            self.title = title
            self.subtitle = subtitle
            self.accessory = accessory
        }
    }

    // MARK: - Configuration

    struct Configuration {
        var iconTint: UIColor = .white
        var iconBackground: UIColor = .tintColor
        var iconCornerRadius: CGFloat = 8
        var iconSize: CGFloat = 30
        var rowCornerRadius: CGFloat = 14
        var background: UIColor = .secondarySystemGroupedBackground
        var highlight: UIColor = .systemFill
        var animation: Inlay.Spring = .snappy
        var hapticsEnabled: Bool = true

        static let `default` = Configuration()
    }

    // MARK: - Callbacks

    var onTap: (() -> Void)?
    var onToggle: ((Bool) -> Void)?

    // MARK: - State

    private let configuration: Configuration
    private let model: Model

    private let container = UIView()
    private let iconTile = UIView()
    private let iconView = UIImageView()
    private let titleLabel = UILabel()
    private let subtitleLabel = UILabel()
    private lazy var switchControl = UISwitch()

    // MARK: - Init

    init(model: Model, configuration: Configuration = .default, onTap: (() -> Void)? = nil) {
        self.model = model
        self.configuration = configuration
        self.onTap = onTap
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.model = Model(icon: nil, title: "")
        self.configuration = .default
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        container.translatesAutoresizingMaskIntoConstraints = false
        container.backgroundColor = configuration.background
        container.layer.cornerRadius = configuration.rowCornerRadius
        container.layer.cornerCurve = .continuous
        container.isUserInteractionEnabled = false
        addSubview(container)

        let icon = makeIconTile()
        let text = makeTextStack()
        let accessory = makeAccessory()

        let row = UIStackView(arrangedSubviews: [icon, text, accessory].compactMap { $0 })
        row.axis = .horizontal
        row.alignment = .center
        row.spacing = 12
        row.translatesAutoresizingMaskIntoConstraints = false
        row.isUserInteractionEnabled = false      // switch handled separately
        container.addSubview(row)

        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),

            row.topAnchor.constraint(equalTo: container.topAnchor, constant: 12),
            row.bottomAnchor.constraint(equalTo: container.bottomAnchor, constant: -12),
            row.leadingAnchor.constraint(equalTo: container.leadingAnchor, constant: 14),
            row.trailingAnchor.constraint(equalTo: container.trailingAnchor, constant: -14),
            heightAnchor.constraint(greaterThanOrEqualToConstant: 56),
        ])

        // The switch needs its own touch handling above the row's.
        if case .toggle = model.accessory {
            switchControl.isUserInteractionEnabled = true
        } else {
            addTarget(self, action: #selector(handleTap), for: .touchUpInside)
        }
    }

    private func makeIconTile() -> UIView {
        iconTile.translatesAutoresizingMaskIntoConstraints = false
        iconTile.backgroundColor = configuration.iconBackground
        iconTile.layer.cornerRadius = configuration.iconCornerRadius
        iconTile.layer.cornerCurve = .continuous

        iconView.translatesAutoresizingMaskIntoConstraints = false
        iconView.tintColor = configuration.iconTint
        iconView.contentMode = .scaleAspectFit
        iconView.preferredSymbolConfiguration = UIImage.SymbolConfiguration(
            pointSize: configuration.iconSize * 0.55, weight: .semibold)
        iconView.image = model.icon
        iconTile.addSubview(iconView)

        NSLayoutConstraint.activate([
            iconTile.widthAnchor.constraint(equalToConstant: configuration.iconSize),
            iconTile.heightAnchor.constraint(equalToConstant: configuration.iconSize),
            iconView.centerXAnchor.constraint(equalTo: iconTile.centerXAnchor),
            iconView.centerYAnchor.constraint(equalTo: iconTile.centerYAnchor),
        ])
        return iconTile
    }

    private func makeTextStack() -> UIView {
        titleLabel.text = model.title
        titleLabel.font = .preferredFont(forTextStyle: .body)
        titleLabel.adjustsFontForContentSizeCategory = true
        titleLabel.textColor = .label

        let stack = UIStackView(arrangedSubviews: [titleLabel])
        stack.axis = .vertical
        stack.alignment = .leading
        stack.spacing = 1

        if let subtitle = model.subtitle {
            subtitleLabel.text = subtitle
            subtitleLabel.font = .preferredFont(forTextStyle: .footnote)
            subtitleLabel.adjustsFontForContentSizeCategory = true
            subtitleLabel.textColor = .secondaryLabel
            subtitleLabel.numberOfLines = 1
            stack.addArrangedSubview(subtitleLabel)
        }
        stack.setContentHuggingPriority(.defaultLow, for: .horizontal)
        return stack
    }

    private func makeAccessory() -> UIView? {
        switch model.accessory {
        case .none:
            return nil
        case .chevron:
            return makeChevron()
        case .value(let text):
            let label = UILabel()
            label.text = text
            label.font = .preferredFont(forTextStyle: .body)
            label.textColor = .secondaryLabel
            let stack = UIStackView(arrangedSubviews: [label, makeChevron()])
            stack.axis = .horizontal
            stack.alignment = .center
            stack.spacing = 6
            return stack
        case .toggle(let isOn):
            switchControl.isOn = isOn
            switchControl.onTintColor = configuration.iconBackground
            switchControl.addTarget(self, action: #selector(switchChanged), for: .valueChanged)
            return switchControl
        }
    }

    private func makeChevron() -> UIImageView {
        let chevron = UIImageView(image: UIImage(systemName: "chevron.right"))
        chevron.tintColor = .tertiaryLabel
        chevron.preferredSymbolConfiguration = UIImage.SymbolConfiguration(
            pointSize: 13, weight: .semibold)
        chevron.setContentHuggingPriority(.required, for: .horizontal)
        return chevron
    }

    // MARK: - Interaction

    override var isHighlighted: Bool {
        didSet {
            guard oldValue != isHighlighted else { return }
            Inlay.SpringAnimator.animate(configuration.animation) {
                self.container.backgroundColor =
                    self.isHighlighted ? self.configuration.highlight : self.configuration.background
                self.transform = self.isHighlighted
                    ? CGAffineTransform(scaleX: 0.98, y: 0.98) : .identity
            }
        }
    }

    @objc private func handleTap() {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        onTap?()
    }

    @objc private func switchChanged() {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        onToggle?(switchControl.isOn)
    }
}

